import { Component } from '@angular/core';
import { CommonModule } from '@angular/common'; 
import { FormsModule } from '@angular/forms';   

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
  services = [
    { title: 'PEDIATRICIANS' },
    { title: 'URANOLOGISTS' },
    { title: 'IMMUNOLOGISTS' }
  ];

  doctors = Array(12).fill(null).map((_, index) => ({
    name: `Doctor M${index + 1}`,
    specialty: 'MBBS, MD'
  }));

  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  // ميزة الانتقال السلس إلى أقسام الصفحة عند الضغط على الأزرار
  scrollToSection(sectionId: string) {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }

  onSignIn() {
    alert('Sign In clicked!');
  }

  onRegister() {
    alert('Register clicked!');
  }

  onPrevSlide() {
    console.log('Slider arrow navigation functional.');
  }

  onSubmit() {
    if (this.contactData.firstName) {
      alert(`Message successfully sent by: ${this.contactData.firstName}`);
      this.contactData = { firstName: '', lastName: '', mobileNumber: '', email: '', message: '' };
    }
  }
}
